import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Payroll & Compensation","description":"","frontmatter":{},"headers":[],"relativePath":"modules/payroll.md","filePath":"modules/payroll.md"}'),n={name:"modules/payroll.md"};function l(s,t,i,d,p,c){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="payroll-compensation" tabindex="-1">Payroll &amp; Compensation <a class="header-anchor" href="#payroll-compensation" aria-label="Permalink to &quot;Payroll &amp; Compensation&quot;">​</a></h1><p>The Payroll module handles the complete compensation lifecycle: defining salary components, building reusable salary structures, assigning compensation packages to employees, running payroll cycles, and generating downloadable payslips. A two-pass calculation engine ensures accurate tax and net pay computations.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Payroll</strong> or <code>/payroll</code>. The module is divided into:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Salary Components</strong></td><td><code>/payroll/components</code></td><td>Individual earning, deduction, and tax components</td></tr><tr><td><strong>Salary Structures</strong></td><td><code>/payroll/structures</code></td><td>Reusable packages built from components</td></tr><tr><td><strong>Employee Salaries</strong></td><td><code>/payroll/employee-salaries</code></td><td>Assign structures + amounts to employees</td></tr><tr><td><strong>Payroll Runs</strong></td><td><code>/payroll/runs</code></td><td>Process payroll for a period</td></tr><tr><td><strong>Payslips</strong></td><td><code>/payroll/payslips</code></td><td>View and download individual payslips</td></tr></tbody></table><hr><h2 id="salary-components" tabindex="-1">Salary Components <a class="header-anchor" href="#salary-components" aria-label="Permalink to &quot;Salary Components&quot;">​</a></h2><p>Salary components are the building blocks of compensation. Each component represents a single line on a payslip — a basic salary, house rent allowance, income tax, provident fund deduction, etc.</p><h3 id="component-types" tabindex="-1">Component Types <a class="header-anchor" href="#component-types" aria-label="Permalink to &quot;Component Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Earning</strong></td><td>Money paid to the employee (adds to gross pay)</td></tr><tr><td><strong>Deduction</strong></td><td>Money subtracted from the gross pay</td></tr><tr><td><strong>Tax</strong></td><td>A special deduction type calculated as a percentage or via a tax slab</td></tr></tbody></table><h3 id="calculation-types" tabindex="-1">Calculation Types <a class="header-anchor" href="#calculation-types" aria-label="Permalink to &quot;Calculation Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Calculation Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Fixed</strong></td><td>A constant amount per period</td><td><code>Basic Salary = 5,000</code></td></tr><tr><td><strong>% of Basic</strong></td><td>A percentage of the Basic Salary component</td><td><code>HRA = 40% of Basic</code></td></tr><tr><td><strong>% of Gross</strong></td><td>A percentage of the total gross earnings</td><td><code>Provident Fund = 8% of Gross</code></td></tr><tr><td><strong>Formula</strong></td><td>A custom formula combining other components</td><td><code>Performance Bonus = Basic × KPI Score</code></td></tr></tbody></table><h3 id="creating-a-salary-component" tabindex="-1">Creating a Salary Component <a class="header-anchor" href="#creating-a-salary-component" aria-label="Permalink to &quot;Creating a Salary Component&quot;">​</a></h3><ol><li>Navigate to <strong>Payroll → Salary Components</strong></li><li>Click <strong>Add Component</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Component Name</strong></td><td>Yes</td><td>e.g., <code>Basic Salary</code>, <code>House Rent Allowance</code></td></tr><tr><td><strong>Short Name</strong></td><td>No</td><td>Abbreviation for payslip (e.g., <code>BASIC</code>, <code>HRA</code>)</td></tr><tr><td><strong>Type</strong></td><td>Yes</td><td>Earning / Deduction / Tax</td></tr><tr><td><strong>Calculation Type</strong></td><td>Yes</td><td>Fixed / % of Basic / % of Gross</td></tr><tr><td><strong>Value</strong></td><td>Yes</td><td>Amount or percentage</td></tr><tr><td><strong>Taxable</strong></td><td>No</td><td>Whether this component is included in taxable income calculation</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Internal notes</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><hr><h2 id="salary-structures" tabindex="-1">Salary Structures <a class="header-anchor" href="#salary-structures" aria-label="Permalink to &quot;Salary Structures&quot;">​</a></h2><p>A salary structure is a named collection of components. You create one structure per employment level or compensation tier, then assign it to multiple employees.</p><h3 id="example-structures" tabindex="-1">Example Structures <a class="header-anchor" href="#example-structures" aria-label="Permalink to &quot;Example Structures&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Structure Name</th><th>Components</th></tr></thead><tbody><tr><td><strong>Junior Staff</strong></td><td>Basic, HRA (40%), Transport (Fixed), Income Tax (15%)</td></tr><tr><td><strong>Senior Staff</strong></td><td>Basic, HRA (50%), Transport (Fixed), Medical (Fixed), Income Tax (20%)</td></tr><tr><td><strong>Management</strong></td><td>Basic, HRA (60%), Car Allowance, Mobile Allowance, Income Tax (25%)</td></tr></tbody></table><h3 id="creating-a-salary-structure" tabindex="-1">Creating a Salary Structure <a class="header-anchor" href="#creating-a-salary-structure" aria-label="Permalink to &quot;Creating a Salary Structure&quot;">​</a></h3><ol><li>Navigate to <strong>Payroll → Salary Structures</strong></li><li>Click <strong>Add Structure</strong></li><li>Enter a <strong>Structure Name</strong></li><li>Add components by clicking <strong>Add Component Row</strong>: <ul><li>Select the component</li><li>Optionally override the default value (e.g., increase the HRA % for this structure)</li></ul></li><li>Click <strong>Save</strong></li></ol><hr><h2 id="assigning-salary-to-an-employee" tabindex="-1">Assigning Salary to an Employee <a class="header-anchor" href="#assigning-salary-to-an-employee" aria-label="Permalink to &quot;Assigning Salary to an Employee&quot;">​</a></h2><p>Before an employee appears in a payroll run, they must have a salary assigned.</p><ol><li>Navigate to <strong>Payroll → Employee Salaries</strong></li><li>Click <strong>Assign Salary</strong></li><li>Select the <strong>Employee</strong></li><li>Select a <strong>Salary Structure</strong></li><li>Enter the <strong>Basic Salary</strong> amount (fixed components and percentages are calculated from this)</li><li>Set the <strong>Effective Date</strong> (the date from which this salary is valid)</li><li>Click <strong>Save</strong></li></ol><p>Salary history is tracked — you can add a new salary record (with a new effective date) to record a raise. The system uses the salary that was effective at the time of the payroll run date.</p><hr><h2 id="running-payroll" tabindex="-1">Running Payroll <a class="header-anchor" href="#running-payroll" aria-label="Permalink to &quot;Running Payroll&quot;">​</a></h2><h3 id="step-1-create-a-payroll-run" tabindex="-1">Step 1: Create a Payroll Run <a class="header-anchor" href="#step-1-create-a-payroll-run" aria-label="Permalink to &quot;Step 1: Create a Payroll Run&quot;">​</a></h3><ol><li>Navigate to <strong>Payroll → Runs</strong></li><li>Click <strong>New Payroll Run</strong></li><li>Configure:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Period</strong></td><td>Month and year (e.g., <code>April 2026</code>)</td></tr><tr><td><strong>Pay Date</strong></td><td>Date employees will be paid</td></tr><tr><td><strong>Department</strong></td><td><code>All</code> or a specific department</td></tr><tr><td><strong>Notes</strong></td><td>Optional internal notes</td></tr></tbody></table><ol start="4"><li>Click <strong>Generate Payroll</strong></li></ol><p>The system:</p><ul><li>Fetches all active employees with salary assignments</li><li>Calculates each component for each employee using the 2-pass engine</li><li>Creates individual payroll records</li><li>Sets the run status to <strong>Draft</strong></li></ul><h3 id="step-2-review-the-draft" tabindex="-1">Step 2: Review the Draft <a class="header-anchor" href="#step-2-review-the-draft" aria-label="Permalink to &quot;Step 2: Review the Draft&quot;">​</a></h3><p>In the Draft state, you can:</p><ul><li>Review individual payslip calculations</li><li>Manually override any component value for specific employees</li><li>Add one-off bonuses or deductions</li><li>Remove specific employees from this run</li></ul><h3 id="step-3-approve-the-payroll-run" tabindex="-1">Step 3: Approve the Payroll Run <a class="header-anchor" href="#step-3-approve-the-payroll-run" aria-label="Permalink to &quot;Step 3: Approve the Payroll Run&quot;">​</a></h3><p>Once you are satisfied with the calculations:</p><ol><li>Click <strong>Approve Run</strong></li><li>Confirm in the dialog</li><li>Status changes to <strong>Approved</strong></li></ol><p>In the Approved state, individual records are locked. No further edits are possible without reverting the run.</p><h3 id="step-4-mark-as-paid" tabindex="-1">Step 4: Mark as Paid <a class="header-anchor" href="#step-4-mark-as-paid" aria-label="Permalink to &quot;Step 4: Mark as Paid&quot;">​</a></h3><p>After bank transfers are completed:</p><ol><li>Click <strong>Mark as Paid</strong></li><li>Optionally upload a payment reference file</li><li>Status changes to <strong>Paid</strong></li></ol><p>Payslips are now available for employees to download from their self-service portal.</p><h3 id="payroll-run-status-flow" tabindex="-1">Payroll Run Status Flow <a class="header-anchor" href="#payroll-run-status-flow" aria-label="Permalink to &quot;Payroll Run Status Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Draft → Approved → Paid</span></span>
<span class="line"><span>      ↑ (Revert to Draft if errors found)</span></span></code></pre></div><hr><h2 id="two-pass-calculation-engine" tabindex="-1">Two-Pass Calculation Engine <a class="header-anchor" href="#two-pass-calculation-engine" aria-label="Permalink to &quot;Two-Pass Calculation Engine&quot;">​</a></h2><p>GeniusHRM uses a two-pass calculation model to ensure accuracy for percentage-based components that depend on totals:</p><h3 id="pass-1-calculate-all-non-dependent-components" tabindex="-1">Pass 1: Calculate All Non-Dependent Components <a class="header-anchor" href="#pass-1-calculate-all-non-dependent-components" aria-label="Permalink to &quot;Pass 1: Calculate All Non-Dependent Components&quot;">​</a></h3><ul><li>All <strong>Fixed</strong> earnings</li><li>All <strong>% of Basic</strong> components (using the assigned basic salary)</li></ul><h3 id="pass-2-calculate-dependent-components" tabindex="-1">Pass 2: Calculate Dependent Components <a class="header-anchor" href="#pass-2-calculate-dependent-components" aria-label="Permalink to &quot;Pass 2: Calculate Dependent Components&quot;">​</a></h3><ul><li><strong>% of Gross</strong> components (using the gross total from Pass 1)</li><li><strong>Tax</strong> calculations (applied after all earnings are summed)</li></ul><p>This ensures that tax and gross-dependent deductions always reference the final, correct totals rather than intermediate values.</p><hr><h2 id="payslip-generation-and-download" tabindex="-1">Payslip Generation and Download <a class="header-anchor" href="#payslip-generation-and-download" aria-label="Permalink to &quot;Payslip Generation and Download&quot;">​</a></h2><p>Payslips are generated for each employee in every payroll run.</p><h3 id="viewing-a-payslip-admin-hr" tabindex="-1">Viewing a Payslip (Admin/HR) <a class="header-anchor" href="#viewing-a-payslip-admin-hr" aria-label="Permalink to &quot;Viewing a Payslip (Admin/HR)&quot;">​</a></h3><ol><li>Navigate to <strong>Payroll → Payslips</strong></li><li>Filter by employee, period, or run</li><li>Click <strong>View</strong> to see the payslip in the browser</li><li>Click <strong>Download PDF</strong> to generate a PDF version</li></ol><h3 id="employee-self-service-payslip-download" tabindex="-1">Employee Self-Service Payslip Download <a class="header-anchor" href="#employee-self-service-payslip-download" aria-label="Permalink to &quot;Employee Self-Service Payslip Download&quot;">​</a></h3><p>Employees can access their own payslips:</p><ol><li>Log in and navigate to <strong>My Profile → My Payslips</strong></li><li>Select the desired period</li><li>Click <strong>Download PDF</strong></li></ol><h3 id="payslip-pdf-contents" tabindex="-1">Payslip PDF Contents <a class="header-anchor" href="#payslip-pdf-contents" aria-label="Permalink to &quot;Payslip PDF Contents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Section</th><th>Content</th></tr></thead><tbody><tr><td><strong>Header</strong></td><td>Company logo, name, address</td></tr><tr><td><strong>Employee Info</strong></td><td>Name, ID, department, position, period</td></tr><tr><td><strong>Earnings</strong></td><td>Itemised list of all earning components</td></tr><tr><td><strong>Deductions</strong></td><td>Itemised list of all deduction components</td></tr><tr><td><strong>Tax</strong></td><td>Calculated tax amount</td></tr><tr><td><strong>Summary</strong></td><td>Gross Pay, Total Deductions, Net Pay</td></tr><tr><td><strong>Footer</strong></td><td>Pay date, payment method</td></tr></tbody></table><hr><h2 id="payroll-reports" tabindex="-1">Payroll Reports <a class="header-anchor" href="#payroll-reports" aria-label="Permalink to &quot;Payroll Reports&quot;">​</a></h2><p>Navigate to <strong>Reports → Payroll</strong> to access:</p><ul><li>Monthly payroll cost by department</li><li>Year-to-date payroll summary</li><li>Component breakdown (what portion is basic vs. allowances)</li><li>Year-over-year comparison chart</li></ul><p>See <a href="/modules/reports.html">Reports &amp; Analytics</a> for full details.</p>`,73)])])}const g=e(n,[["render",l]]);export{u as __pageData,g as default};
